import React, { useEffect, useState } from 'react';
import axios from 'axios';

const DoctorDashboard = () => {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  const [todaysAppointments, setTodaysAppointments] = useState([]);
  const [appointmentHistory, setAppointmentHistory] = useState([]);
  const [availability, setAvailability] = useState([]);
  const [patients, setPatients] = useState([]);
  const [editProfile, setEditProfile] = useState(false);
  const [profile, setProfile] = useState({ name: '', specialization: '', bio: '' });
  const [newAvailabilityDate, setNewAvailabilityDate] = useState('');
  const [newAvailabilityTime, setNewAvailabilityTime] = useState('');

  useEffect(() => {
    const fetchUser = async () => {
      try {
        const response = await axios.get('/api/auth/me', { withCredentials: true });
        setUser(response.data);
        setProfile({
          name: response.data.name || '',
          specialization: response.data.specialization || '',
          bio: response.data.bio || '',
        });
      } catch (err) {
        setError('⚠️ Failed to load user profile.');
      } finally {
        setLoading(false);
      }
    };
    fetchUser();
  }, []);

  useEffect(() => {
    if (user && user.role === 'Doctor') {
      const fetchDashboardData = async () => {
        try {
          const [apptRes, histRes, availRes, patRes] = await Promise.all([
            axios.get('/api/doctor/today-appointments'),
            axios.get('/api/doctor/appointment-history'),
            axios.get('/api/doctor/availability'),
            axios.get('/api/doctor/patients')
          ]);
          setTodaysAppointments(apptRes.data);
          setAppointmentHistory(histRes.data);
          setAvailability(availRes.data);
          setPatients(patRes.data);
        } catch (err) {
          console.error('Error loading dashboard data:', err);
        }
      };
      fetchDashboardData();
    }
  }, [user]);

  const handleAddAvailability = async () => {
    if (!newAvailabilityDate || !newAvailabilityTime) {
      alert('Please select date and time');
      return;
    }
    try {
      const response = await axios.post('/api/doctor', {
        date: newAvailabilityDate,
        timeSlot: newAvailabilityTime,
      });
      setAvailability((prev) => [...prev, response.data]);
      setNewAvailabilityDate('');
      setNewAvailabilityTime('');
    } catch (err) {
      alert('Failed to add availability');
    }
  };

  const handleProfileChange = (e) => {
    setProfile({ ...profile, [e.target.name]: e.target.value });
  };

  const handleProfileSubmit = async (e) => {
    e.preventDefault();
    try {
      await axios.put('/api/auth/profile', profile);
      setEditProfile(false);
      alert('Profile updated successfully');
    } catch (err) {
      alert('Error updating profile');
    }
  };

  const handleStatusChange = async (id, newStatus) => {
    try {
      await axios.put(`/api/bookings/${id}/status`, { status: newStatus });
      setTodaysAppointments((prev) =>
          prev.map((appt) => (appt._id === id ? { ...appt, status: newStatus } : appt))
      );
    } catch (err) {
      alert('Failed to update status');
    }
  };

  if (loading) {
    return (
        <div className="flex justify-center items-center min-h-screen bg-gradient-to-br from-green-50 to-blue-100">
          <p className="text-gray-600 text-lg">Loading profile...</p>
        </div>
    );
  }

  if (error) {
    return (
        <div className="flex justify-center items-center min-h-screen bg-gradient-to-br from-green-50 to-blue-100">
          <p className="text-red-600 text-lg font-semibold">{error}</p>
        </div>
    );
  }

  if (!user) {
    return (
        <div className="flex justify-center items-center min-h-screen bg-gradient-to-br from-green-50 to-blue-100">
          <p className="text-gray-500 text-lg">No user data available.</p>
        </div>
    );
  }

  if (user.role !== 'Doctor') {
    return (
        <div className="flex justify-center items-center min-h-screen bg-gradient-to-br from-red-100 to-yellow-100">
          <p className="text-red-600 text-lg font-semibold">Access Denied: Doctors Only</p>
        </div>
    );
  }

  return (
      <div className="min-h-screen bg-gray-100 p-6 text-gray-900 max-w-7xl mx-auto">
        <h1 className="text-3xl font-bold mb-6 text-center text-blue-700">Doctor Dashboard</h1>
        {/* Add appointment cards, availability, patient list, and profile editor as needed */}
      </div>
  );
};

export default DoctorDashboard;
